+        let mut pool = MemoryPool::new(config);
+        assert!((pool.utilization() - 0.0).abs() < 1e-10);
+        pool.allocate();
+        assert!((pool.utilization() - 0.25).abs() < 1e-10);
+        pool.allocate();
+        assert!((pool.utilization() - 0.5).abs() < 1e-10);
+    }
